export function validate_phone(phone: string): FieldError | undefined {
  const trimmed = phone.trim();
  if (trimmed.length === 0) {
    return { message: 'El teléfono es requerido' };
  }
  if (!PHONE_REGEX.test(trimmed)) {
    return { message: PHONE_ERROR_MSG };
  }
  return undefined;
}
